#include <iostream>
#include <vector>

using namespace std;

struct TreeNode {
    int data;
    TreeNode *left, *right;
    TreeNode(int x) : data(x), left(NULL), right(NULL) {}
};

bool createTree(vector<int>& arr, TreeNode*& root) {
    if (!arr.empty()) {
        root = new TreeNode(arr[0]);
        arr.erase(arr.begin());
        root->left = createTree(arr, root->left);
        root->right = createTree(arr, root->right);
        return true;
    }
    return false;
}

TreeNode* solution(TreeNode* root, int target_data) {
    if (!root) {
        return NULL;
    }
    if (root->data == target_data) {
        // TO DO: Delete the target node
        return NULL;
    }
    root->left = solution(root->left, target_data);
    root->right = solution(root->right, target_data);
    return root;
}

int main() {
    vector<int> arr = {8, 3, 10, 1, 6, 14, 4, 7, 15};
    TreeNode* root;
    createTree(arr, root);
    TreeNode* newRoot = solution(root, 3);
    // Print the modified binary tree
    printTree(newRoot);

    return 0;
}

void printTree(TreeNode* root) {
    if (root) {
        printTree(root->right);
        cout << root->data << " ";
        printTree(root->left);
    }
}
